patch:
--- a/comparator.sv
+++ b/comparator.sv
@@ -1,9 +1,9 @@
 module comparator_32bit (
-  output eq,
-  output lt,
   input [31:0] a,
   input [31:0] b,
+  output eq,
+  output lt,
   output gt
 );
   assign eq = (a == b);
   assign lt = (a < b);
   assign gt = (a > b);

before_code:
module comparator_32bit (
  output eq,
  output lt,
  input [31:0] a,
  input [31:0] b,
  output gt
);
  assign eq = (a == b);
  assign lt = (a < b);
  assign gt = (a > b);
endmodule

module alu_top (
  input [31:0] x, y,
  output equal, less_than, greater_than
);
  comparator_32bit cmp_inst (
    .a(x),
    .b(y),
    .eq(equal),
    .lt(less_than),
    .gt(greater_than)
  );
endmodule

after_code:
module comparator_32bit (
  input [31:0] a,
  input [31:0] b,
  output eq,
  output lt,
  output gt
);
  assign eq = (a == b);
  assign lt = (a < b);
  assign gt = (a > b);
endmodule

